    private EzCheckRequest getEzcheckRequest(){
        if(ifTest) {
            if(!ifNewPlatform) return EzReceipt.getTestAccountEzCheckRequest();
            return EzReceipt.getNewPlatformTestAccountEzCheckRequest();
        }

        EzCheckRequest req = new EzCheckRequest();
        if(!ifNewPlatform) {
            req.setProtocol("https");
            req.setUrl(".coimapi.net");
        }
        req.setComNum(comNum);
        req.setStoreId(storeId);
        req.setApiKey(key);
        req.setAccountNo(accountNo);
        req.setPwd(pwd);
        req.isTestAccount(false);

        return req;
    }

    private EzReceiptRequest getInvoiceRequest(APIEntry e, String prefix){
        EzReceiptRequest ir = new EzReceiptRequest();
        ir.setName(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "name"),"1"));
        ir.setEmail(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "email"),"1"));
        ir.setAddr(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "addr"),"1"));
        ir.setCdc4(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "cdc4"),"1"));
        ir.setPhone(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "phone"),"1"));
        String invoiceDateString = e.getFieldValueByAttribute(String.format("%s_%s", prefix, "date"),"1");
        if(invoiceDateString!=null && !invoiceDateString.isEmpty())
            ir.setInvoiceDate(Encoder.parseStandardDate(invoiceDateString));

        String carrierTypeText = e.getFieldValueByAttribute(String.format("%s_%s", prefix, "carrierType"),"1");
        ir.setCarrierType(carrierTypeMapper(carrierTypeText));
        ir.setAccName(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "accName"),"1"));
        ir.setMobileCode(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "mobileCode"),"1"));

        ir.setInvNid(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "invNID"),"1"));
        ir.setInvTitle(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "invTitle"),"1"));
        ir.setInvAddr(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "invAddr"),"1"));
        ir.setInvReceiver(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "invReceiver"),"1"));

        ir.setRemark(e.getFieldValueByAttribute(String.format("%s_%s", prefix, "remark"),"1"));

        String type = e.getFieldValueByAttribute(String.format("%s_%s", prefix, "type"),"1");

        type = (type == null || type.isEmpty()) ? "1": type.substring(0, type.indexOf(":"));
        ir.setType(type);

        return ir;
    }

    private int carrierTypeMapper(String selectText){
        if(selectText == null || selectText.isEmpty()) return EzReceipt.UnknowCarrier;
        if("會員載具".equals(selectText)) return EzReceipt.Membership;
        if("手機條碼".equals(selectText)) return EzReceipt.MobileBarcode;

        return EzReceipt.Receipt;
    }


